mapper.delete:
	DELETE FROM message_statistics_timeseries
	WHERE server_id = #{serverId}
  	AND bucket_size_minutes = #{bucketSizeMinutes}
  	AND ts = #{ts}

DELETE FROM message_statistics_timeseries
WHERE server_id = #{serverId}
   AND bucket_size_minutes = #{bucketSizeMinutes}
   AND ts  <  #{cutoffTs}

mapper.select:
   SELECT id, channel_id, connector_id, ts, bucket_size_minutes, received, filtered, queued, sent, error, server_id
 	FROM message_statistics_timeseries
	WHERE server_id = #{serverId}
  		AND channel_id = #{channelId}
  		AND connector_id = ''
  		AND bucket_size_minutes = #{intervalMinutes}
       AND ts  >=  #{startTs} 
         AND ts  <   #{endTs}   
	ORDER BY ts ASC

SELECT id, channel_id, connector_id, ts, bucket_size_minutes, received, filtered, queued, sent, error, server_id
FROM message_statistics_timeseries
WHERE server_id = #{serverId}
   AND channel_id = #{channelId}
   AND connector_id = #{connectorId}
   AND bucket_size_minutes = #{intervalMinutes}
    AND ts  >=  #{startTs} 
      AND ts  <   #{endTs}   
ORDER BY ts ASC

SELECT id, channel_id, connector_id, ts, bucket_size_minutes, received, filtered, queued, sent, error, server_id
FROM message_statistics_timeseries
WHERE server_id = #{serverId}
   AND bucket_size_minutes = #{intervalMinutes}
    AND ts  >=  #{startTs} 
      AND ts  <   #{endTs}   
ORDER BY ts ASC
